106	        {
107	            bool hasReachedLimit = false;
108	            while (await rs.ReadAsync(cancellationToken).ConfigureAwait(false) && !hasReachedLimit)
109	            {
110	                if (resultList.Count == count)
111	                {
112	                    hasReachedLimit = true;
113	                }
114	                else
115	                {
116	                    string triggerName = rs.GetString(ColumnTriggerName)!;
117	                    string groupName = rs.GetString(ColumnTriggerGroup)!;
118	                    resultList.Add(new TriggerKey(triggerName, groupName));
119	                }
120	            }
121	
122	            return hasReachedLimit;
123	        }
