172	    /// <inheritdoc />
173	    public virtual async ValueTask<List<IOperableTrigger>> SelectTriggersForRecoveringJobs(ConnectionAndTransactionHolder conn, CancellationToken cancellationToken = default)
174	    {
175	        List<IOperableTrigger> triggers = [];
176	        List<FiredTriggerRecord> triggerData = [];
177	        List<TriggerKey> keys = [];
178	
179	        using (var cmd = PrepareCommand(conn, ReplaceTablePrefix(SqlSelectInstancesRecoverableFiredTriggers)))
180	        {
181	            AddCommandParameter(cmd, "schedulerName", schedName);
182	            AddCommandParameter(cmd, "instanceName", instanceId);
183	            AddCommandParameter(cmd, "requestsRecovery", GetDbBooleanValue(true));
184	
185	            using (var rs = await cmd.ExecuteReaderAsync(cancellationToken).ConfigureAwait(false))
186	            {
187	                long dumId = timeProvider.GetTimestamp();
188	
189	                while (await rs.ReadAsync(cancellationToken).ConfigureAwait(false))
190	                {
191	                    string jobName = rs.GetString(ColumnJobName)!;
192	                    string jobGroup = rs.GetString(ColumnJobGroup)!;
193	                    string trigName = rs.GetString(ColumnTriggerName)!;
194	                    string trigGroup = rs.GetString(ColumnTriggerGroup)!;
195	                    int priority = Convert.ToInt32(rs[ColumnPriority], CultureInfo.InvariantCulture);
196	                    DateTimeOffset firedTime = GetDateTimeFromDbValue(rs[ColumnFiredTime]) ?? DateTimeOffset.MinValue;
197	                    DateTimeOffset scheduledTime = GetDateTimeFromDbValue(rs[ColumnScheduledTime]) ?? DateTimeOffset.MinValue;
198	                    SimpleTriggerImpl rcvryTrig = new SimpleTriggerImpl("recover_" + instanceId + "_" + Convert.ToString(dumId++, CultureInfo.InvariantCulture),
199	                        SchedulerConstants.DefaultRecoveryGroup, scheduledTime);
200	                    rcvryTrig.JobKey = new JobKey(jobName, jobGroup);
201	                    rcvryTrig.Priority = priority;
202	                    rcvryTrig.MisfireInstruction = MisfireInstruction.IgnoreMisfirePolicy;
203	
204	                    var dataHolder = new FiredTriggerRecord
205	                    {
206	                        ScheduleTimestamp = scheduledTime,
207	                        FireTimestamp = firedTime
208	                    };
209	
210	                    triggerData.Add(dataHolder);
211	                    triggers.Add(rcvryTrig);
212	                    keys.Add(new TriggerKey(trigName, trigGroup));
213	                }
214	            }
215	        }
216	
217	        // read JobDataMaps with different reader..
218	        for (int i = 0; i < triggers.Count; i++)
219	        {
220	            IOperableTrigger trigger = triggers[i];
221	            TriggerKey key = keys[i];
222	            FiredTriggerRecord dataHolder = triggerData[i];
223	
224	            // load job data map and transfer information
225	            JobDataMap jd = await SelectTriggerJobDataMap(conn, key, cancellationToken).ConfigureAwait(false);
226	            jd.Put(SchedulerConstants.FailedJobOriginalTriggerName, key.Name);
227	            jd.Put(SchedulerConstants.FailedJobOriginalTriggerGroup, key.Group);
228	            jd.Put(SchedulerConstants.FailedJobOriginalTriggerFiretime, Convert.ToString(dataHolder.FireTimestamp, CultureInfo.InvariantCulture)!);
229	            jd.Put(SchedulerConstants.FailedJobOriginalTriggerScheduledFiretime, Convert.ToString(dataHolder.ScheduleTimestamp, CultureInfo.InvariantCulture)!);
230	            trigger.JobDataMap = jd;
231	        }
232	
233	        return triggers;
234	    }
