                .WithReturnType<Task<DbDataReader>>()
                .Returns(Task.FromResult(dataReader));
            A.CallTo(command).Where(x => x.Method.Name == "get_DbParameterCollection")
                .WithReturnType<DbParameterCollection>()
                .Returns(new StubParameterCollection());
            A.CallTo(command).Where(x => x.Method.Name == "CreateDbParameter")
                .WithReturnType<DbParameter>()
                .Returns(new SqlParameter());
            A.CallTo(() => dataReader.ReadAsync(cancellationToken)).Returns(true);
            A.CallTo(() => dataReader.GetString(AdoConstants.ColumnJobName)).Returns("test-job");
            A.CallTo(() => dataReader.GetString(AdoConstants.ColumnJobGroup)).Returns(SchedulerConstants.DefaultGroup);
            A.CallTo(() => dataReader.GetString(AdoConstants.ColumnDescription)).Returns(null);
            A.CallTo(() => dataReader.GetString(AdoConstants.ColumnTriggerType)).Returns(AdoConstants.TriggerTypeBlob);
            A.CallTo(() => dataReader.GetString(AdoConstants.ColumnCalendarName)).Returns(null);
            A.CallTo(() => dataReader.GetInt32(AdoConstants.ColumnMifireInstruction)).Returns(MisfireInstruction.SmartPolicy);
            A.CallTo(() => dataReader.GetInt32(AdoConstants.ColumnPriority)).Returns(TriggerConstants.DefaultPriority);
            A.CallTo(() => dataReader[AdoConstants.ColumnNextFireTime]).Returns(new DateTimeOffset(2026, 1, 2, 3, 4, 5, TimeSpan.Zero).UtcTicks);
            A.CallTo(() => dataReader[AdoConstants.ColumnPreviousFireTime]).Returns(new DateTimeOffset(2026, 1, 1, 3, 4, 5, TimeSpan.Zero).UtcTicks);
            A.CallTo(() => dataReader[AdoConstants.ColumnStartTime]).Returns(new DateTimeOffset(2025, 12, 31, 3, 4, 5, TimeSpan.Zero).UtcTicks);
            A.CallTo(() => dataReader[AdoConstants.ColumnEndTime]).Returns(DBNull.Value);
            A.CallTo(() => dataReader[AdoConstants.ColumnMisfireOriginalFireTime]).Returns(DBNull.Value);
            A.CallTo(() => dataReader.IsDBNullAsync(11, cancellationToken)).Returns(true);
            A.CallTo(() => dataReader.IsDBNull(0)).Returns(false);

            DbProvider = dbProvider;
            return await base.SelectTrigger(conn, triggerKey, cancellationToken);
        }
    }

